// QR 生成的 SVG/canvas 落到 shadowRoot 容器
import QRCodeStyling from 'https://cdn.jsdelivr.net/npm/qr-code-styling@1/+esm';
const opt={type:'svg',width:256,height:spec.height??256,...data.options};
const host=document.createElement('div'); host.style.cssText=`width:${opt.width}px;height:${opt.height}px;max-width:100%`; shadowRoot.appendChild(host);
const qr=new QRCodeStyling(opt);
qr.append(host);

